import{_ as t}from"./chunks/lekt0401.veXHzs2X.js";import{_ as e,o as n,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"Lektion 4","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion04.md","filePath":"lektionen/lektion04.md"}'),d={name:"lektionen/lektion04.md"};function s(o,a,u,l,m,h){return n(),r("div",null,[...a[0]||(a[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-4" tabindex="-1">Lektion 4 <a class="header-anchor" href="#lektion-4" aria-label="Permalink to &quot;Lektion 4&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Gesprochenes Sanskrit</p><ul><li>4.1. Einfache Ergänzungsfragen (Wortfragen) und Antworten <ul><li>4.1.1. Fragepronomina (praśnārthakasarvanāma n.) und Demonstrativpronomina (nidarśakasarvanāma n.) = प्रश्नार्थकसर्वनाम निदर्शकसर्वनामानि च <ul><li>1.1.1.Fragepronomen (praśnārthakasarvanāma n. = प्रश्नार्थकसर्वनामन्)</li><li>4.1.1.2. Demonstrativponomina (nidarśakasarvanāmāni n. = निदर्शकसर्वनामानि)</li></ul></li><li>4.1.2. Sandhi von auslautendem -m</li><li>4.1.3. Sandhi von auslautendem -e</li><li>4.1.4. Sandhi von auslautendem -d</li><li>4.1.5. Frageformeln</li></ul></li><li>4.2. Übung</li></ul><h2 id="gesprochenes-sanskrit" tabindex="-1">Gesprochenes Sanskrit <a class="header-anchor" href="#gesprochenes-sanskrit" aria-label="Permalink to &quot;Gesprochenes Sanskrit&quot;">​</a></h2><h2 id="_4-1-einfache-erganzungsfragen-wortfragen-und-antworten" tabindex="-1">4.1. Einfache Ergänzungsfragen (Wortfragen) und Antworten <a class="header-anchor" href="#_4-1-einfache-erganzungsfragen-wortfragen-und-antworten" aria-label="Permalink to &quot;4.1. Einfache Ergänzungsfragen (Wortfragen) und Antworten&quot;">​</a></h2><h3 id="_4-1-1-fragepronomina-prasnarthakasarvanama-n-und-demonstrativpronomina-nidarsakasarvanama-n-प्रश्नार्थकसर्वनाम-निदर्शकसर्वनामानि-च" tabindex="-1">4.1.1. Fragepronomina (praśnārthakasarvanāma n.) und Demonstrativpronomina (nidarśakasarvanāma n.) = प्रश्नार्थकसर्वनाम निदर्शकसर्वनामानि च <a class="header-anchor" href="#_4-1-1-fragepronomina-prasnarthakasarvanama-n-und-demonstrativpronomina-nidarsakasarvanama-n-प्रश्नार्थकसर्वनाम-निदर्शकसर्वनामानि-च" aria-label="Permalink to &quot;4.1.1. Fragepronomina (praśnārthakasarvanāma n.) und Demonstrativpronomina (nidarśakasarvanāma n.) = प्रश्नार्थकसर्वनाम निदर्शकसर्वनामानि च&quot;">​</a></h3><h3 id="_1-1-1-fragepronomen-prasnarthakasarvanama-n-प्रश्नार्थकसर्वनामन्" tabindex="-1">1.1.1.Fragepronomen (praśnārthakasarvanāma n. = प्रश्नार्थकसर्वनामन्) <a class="header-anchor" href="#_1-1-1-fragepronomen-prasnarthakasarvanama-n-प्रश्नार्थकसर्वनामन्" aria-label="Permalink to &quot;1.1.1.Fragepronomen (praśnārthakasarvanāma n. = प्रश्नार्थकसर्वनामन्)&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>Nominativ singular</th><th>Nominativ plural</th></tr></thead><tbody><tr><td>Neutrum</td><td>kim = किम्</td><td>kāni = कानि</td></tr><tr><td>Maskulinum</td><td>kas = कस्</td><td>ke = के</td></tr><tr><td>Feminimum</td><td>kā = का</td><td>kās = कास्</td></tr></tbody></table><h3 id="_4-1-1-2-demonstrativponomina-nidarsakasarvanamani-n-निदर्शकसर्वनामानि" tabindex="-1">4.1.1.2. Demonstrativponomina (nidarśakasarvanāmāni n. = निदर्शकसर्वनामानि) <a class="header-anchor" href="#_4-1-1-2-demonstrativponomina-nidarsakasarvanamani-n-निदर्शकसर्वनामानि" aria-label="Permalink to &quot;4.1.1.2. Demonstrativponomina (nidarśakasarvanāmāni n. = निदर्शकसर्वनामानि)&quot;">​</a></h3><table><tbody><tr><td colspan="4">**Stämme**</td></tr><tr><td></td><td>**tad = तद् &quot;er, sie, es; der, die, das&quot; (Erwähnte)**</td><td>**etad = एतद् &quot;dieser, diese, dieses&quot; (dem Sprechenden sehr Nahe)**</td><td>**idam = इदम् &quot;dieser, diese, dieses&quot; (Nahe)**</td></tr><tr><td colspan="4">**Nominativ singular**</td></tr><tr><td>**Neutrum**</td><td>**tad = तद्**</td><td>**etad = एतद्**</td><td>**idam = इदम्**</td></tr><tr><td>**Maskulinum**</td><td>**sa, so saḥ = स सो सः**</td><td>**eṣa, eṣo, eṣaḥ = एष एषो एषः**</td><td>**ayam = अयम्**</td></tr><tr><td>**Femininum**</td><td>**sā = सा**</td><td>**eṣā = एषा**</td><td>**iyam = इयम्**</td></tr><tr><td></td><td></td><td></td><td></td></tr><tr><td colspan="4">**Nominativ plural**</td></tr><tr><td>**Neutrum**</td><td>**tāni = तानि**</td><td>**etāni = एतानि**</td><td>**imāni = इमानि**</td></tr><tr><td>**Maskulinum**</td><td>**te = ते**</td><td>**ete = एते**</td><td>**ime = इमे**</td></tr><tr><td>**Femininum**</td><td>**tās = तास्**</td><td>**etās = एतास्**</td><td>**imās इमास्**</td></tr></tbody></table><p>Zum Nom. sg. mask.:</p><ul><li>sa, eṣa (स एष) steht vor allen Lauten außer kurzem -a</li><li>so, eṣo (सो एषो) steht vor -a, welches mit Avagraha elidiert (ausfällt)</li><li>saḥ, eṣaḥ (सः एषः) steht nur in Pausa (Satzende, Versende)</li></ul><p>Um mit diesen Pronomina (sarvanāman n.) Sätze bilden zu können, ist noch die Kenntnis folgender Sandhiregeln nötig:</p><h3 id="_4-1-2-sandhi-von-auslautendem-m" tabindex="-1">4.1.2. Sandhi von auslautendem -m <a class="header-anchor" href="#_4-1-2-sandhi-von-auslautendem-m" aria-label="Permalink to &quot;4.1.2. Sandhi von auslautendem -m&quot;">​</a></h3><p>Auslautendes -m wird vor Konsonanten durch Anusvāra (-ṃ) ersetzt. Am Satz- bzw. Versende und vor Vokalen bleibt -m erhalten.</p><h3 id="_4-1-3-sandhi-von-auslautendem-e" tabindex="-1">4.1.3. Sandhi von auslautendem -e <a class="header-anchor" href="#_4-1-3-sandhi-von-auslautendem-e" aria-label="Permalink to &quot;4.1.3. Sandhi von auslautendem -e&quot;">​</a></h3><ol><li>vor a- bleibt -e unverändert: das anlautende a- elidiert mit Avagraha:<br> z.B. ete + agnayas » ete &#39;gnayaḥ = एते ऽग्नयः &quot;Diese Feuer&quot;</li><li>Vor anderen Vokalen als kurzem a- wird -e gewöhnlich durch -a mit Hiatus ersetzt. Auch die Ersetzung durch -ay kommt vor<br> z.B. ime + īśvarās » ima īśvarāḥ = इम ईश्वराः (selten: imay īśvarāh = इमयीश्वराः) &quot;Diese HERREN&quot;</li></ol><h3 id="_4-1-4-sandhi-von-aulautendem-d" tabindex="-1">4.1.4. Sandhi von aulautendem -d <a class="header-anchor" href="#_4-1-4-sandhi-von-aulautendem-d" aria-label="Permalink to &quot;4.1.4. Sandhi von aulautendem -d&quot;">​</a></h3><p>Auslautendes -d wird in Pausa sowie vor stimmlosen Gutturalen (k, kh) und Labialen (p, ph) durch -t ersetzt.</p><p>Die Ersetzung vor anderen Konsonanten wird später besprochen. Vermeiden Sie vorläufig solche Lautzusammenstöße!</p><p>Mittels dieser Pronomina bildet man z.B. folgende</p><h3 id="_4-1-5-frageformeln" tabindex="-1">4.1.5. Frageformeln <a class="header-anchor" href="#_4-1-5-frageformeln" aria-label="Permalink to &quot;4.1.5. Frageformeln&quot;">​</a></h3><table><tbody><tr><td rowspan="3">Singular</td><td>Neutrum</td><td>tat kim? /kiṃ tat?<br>तत्किम्, किं तत्etat kim? /kim etat?<br>एतत्किम्, किमेतत्<br>idaṃ kim? / kim idam<br>इदं किम्, किमिदम्</td><td>&quot;Was ist das?&quot;</td></tr><tr><td>Maskulinum</td><td>sa kaḥ? / kaḥ saḥ?<br>स कः, कः सःeṣa kaḥ? / ka eṣaḥ<br>एष कः, क एषः<br>ayaṃ kaḥ? / ko &#39;yam?<br>अयं कः, को ऽयम्</td><td>&quot;Wer ist das?&quot;<br>&quot;Was ist der?</td></tr><tr><td>Femininum</td><td>sā kā? / kā sā?<br>सा का, का साeṣā kā? / kaiṣā? (= kā + eṣā)<br>एषा का, कैषा<br>iyaṃ kā? keyam? (= kā + iyam)<br>इयं का, केयम्</td><td>&quot;Wer ist das?&quot;<br>&quot;Wer ist die?&quot;</td></tr><tr><td rowspan="3">Plural</td><td>Neutrum</td><td>tāni kāni? / kāni tāni?<br>तानि कानि, कानि तानिetāni kāni? / kāny etāni?<br>एतानि कानि, कान्येतानि<br>imāni kāni? / kānīmāni? (= kāni + imāni)<br>इमानि कानि, कानीमानि</td><td></td></tr><tr><td>Maskulinum</td><td>te ke? / ke te?<br>ते के, के तेete ke? ka ete?<br>एते के, क एते<br>ime ke? / ka ime?<br>इमे के, क इमे</td><td></td></tr><tr><td>Femininum</td><td>tāḥ kāh? / kās tāḥ?<br>ताः काः, कास्ताःetāḥ kāḥ? / kā etāḥ?<br>एताः काः, का एताः<br>imāḥ kāḥ? / kā imāḥ?<br>ईमाः काः, का इमाः</td><td></td></tr></tbody></table><p>Ein Beispiel anderer Fragen:</p><blockquote><p>viṣṇuḥ kaḥ? = विष्णुः कः Antwort: viṣṇur īśvaraḥ = विष्णुरीश्वरः. (Hier kann man im Nominalsatz das Subjekt z.B.an den Anfang stellen, um den Anschluss an die Frage zu betonen.)</p></blockquote><p>ANMERKUNG: Die Antworten, die Sie mit Ihren bisherigen Sanskritkenntnissen auf solche Fragen geben können, entsprechen selbstverständlich noch nicht in jeder Hinsicht idiomatisch gutem Sanskrit.</p><h2 id="_4-2-ubung" tabindex="-1">4.2. Übung <a class="header-anchor" href="#_4-2-ubung" aria-label="Permalink to &quot;4.2. Übung&quot;">​</a></h2><p>A) Bilden Sie mündlich mit folgenden Wörtern Fragen nach dem Schema viṣṇuḥ kaḥ (विष्णुः कः) und beantworten Sie die Fragen auf Sanskrit:</p><p>śruti, śiva, brāhmaṇa, dvija (plural), indrāṇī, dhenu, tulādhara, kālidāsa</p><p>= श्रुति, शिव, ब्राह्मण, द्विज (बहुवचनम्), इन्द्राणी, धेनु, तुलाधर, कालिदास</p><p>B) Bilden Sie zur folgenden Leseübung Fragen nach dem Muster etat kim (एतत्किम्) und beantworten Sie die Fragen mit den angegebenen Wörtern und Demonstrativpronomen z.B. eṣa bālaḥ (एष बालः):</p><p><img src="'+t+'" alt=""></p>',34)])])}const c=e(d,[["render",s]]);export{b as __pageData,c as default};
